// All WordPress posts come in from the HTTP Request node (first input)
// All already-processed rows come in from the Google Sheets read node (second input)
const posts = $items('Get WordPress Posts');
const processedRows = $items('Get Processed IDs');

const processedIds = processedRows
  .map(row => row.json.wp_post_id)
  .filter(id => id !== undefined && id !== null && id !== '')
  .map(id => String(id));

return posts.filter(item => !processedIds.includes(String(item.json.id)));

// Parse the AI agent's JSON output AND re-attach the original WordPress post id
// (the id would otherwise be lost, since the AI Agent node only outputs generated text)
return items.map((item, i) => {
  const raw = item.json.output
    .replace(/```json|```/g, '')
    .trim();

  const data = JSON.parse(raw);

  const originalPost = $('Filter New Posts').all()[i];
  data.wp_post_id = originalPost ? originalPost.json.id : null;

  return { json: data };
});

const itemsData = $items("Parse AI JSON");

const toHtml = (text) => {
  if (!text) return "";

  if (Array.isArray(text)) {
    return `
      <ul>
        ${text.map(item => `<li>${item}</li>`).join("")}
      </ul>
    `;
  }

  return `<p>${String(text).replace(/\n/g, "<br>")}</p>`;
};


